// Auto-generated — proverbios (NVI)
// Do NOT edit manually. Re-run scripts/download-bible.mjs to update.

export const PROVERBIOS_NVI: Record<number, string[]> = {
  1: ["Proverbios de Salomón hijo de David, rey de Israel:","para adquirir sabiduría y disciplina; para discernir palabras de inteligencia;","para recibir la corrección que dan la prudencia, la rectitud, la justicia y la equidad;","para infundir sagacidad en los inexpertos, conocimiento y discreción en los jóvenes.","Escuche esto el sabio, y aumente su saber; reciba dirección el entendido,","para discernir el proverbio y la parábola, los dichos de los sabios y sus enigmas.","El temor del SEÑOR es el principio del conocimiento; los necios desprecian la sabiduría y la disciplina.","Hijo mío, escucha las correcciones de tu padre y no abandones las enseñanzas de tu madre.","Adornarán tu cabeza como una diadema; adornarán tu cuello como un collar.","Hijo mío, si los pecadores quieren engañarte, no vayas con ellos.","Estos te dirán: «¡Ven con nosotros! Acechemos a algún inocente y démonos el gusto de matar a algún incauto;","traguémonos a alguien vivo, como se traga el sepulcro a la gente; devorémoslo entero, como devora la fosa a los muertos.","Obtendremos toda clase de riquezas; con el botín llenaremos nuestras casas.","Comparte tu suerte con nosotros, y compartiremos contigo lo que obtengamos».","¡Pero no te dejes llevar por ellos,[1] hijo mío! ¡Apártate de sus senderos!","Pues corren presurosos a hacer lo malo; ¡tienen prisa por derramar sangre!","De nada sirve tender la red a la vista de todos los pájaros,","pero aquellos acechan su propia vida[2] y acabarán por destruirse a sí mismos.","Así terminan los que van tras ganancias mal habidas; por estas perderán la vida.","Clama la sabiduría en las calles; en los lugares públicos levanta su voz.","Clama en las esquinas de calles transitadas; a la entrada de la ciudad razona:","«¿Hasta cuándo, muchachos inexpertos, seguirán aferrados a su inexperiencia? ¿Hasta cuándo, ustedes los insolentes, se complacerán en su insolencia? ¿Hasta cuándo, ustedes los necios, aborrecerán el conocimiento?","Respondan a mis reprensiones, y yo les abriré mi corazón;[3] les daré a conocer mis pensamientos.","Como ustedes no me atendieron cuando los llamé, ni me hicieron caso cuando les tendí la mano,","sino que rechazaron todos mis consejos y no acataron mis reprensiones,","ahora yo me burlaré de ustedes cuando caigan en desgracia. Yo seré quien se ría de ustedes cuando les sobrevenga el miedo,","cuando el miedo les sobrevenga como una tormenta y la desgracia los arrastre como un torbellino.","»Entonces me llamarán, pero no les responderé; me buscarán, pero no me encontrarán.","Por cuanto aborrecieron el conocimiento y no quisieron temer al SEÑOR;","por cuanto no siguieron mis consejos, sino que rechazaron mis reprensiones,","cosecharán el fruto de su conducta, se hartarán con sus propias intrigas;","¡su descarrío e inexperiencia los destruirán, su complacencia y necedad los aniquilarán!","Pero el que me obedezca vivirá tranquilo, sosegado y sin temor del mal»."],
  2: ["Hijo mío, si haces tuyas mis palabras y atesoras mis mandamientos;","si tu oído inclinas hacia la sabiduría y de corazón te entregas a la inteligencia;","si llamas a la inteligencia y pides discernimiento;","si la buscas como a la plata, como a un tesoro escondido,","entonces comprenderás el temor del SEÑOR y hallarás el conocimiento de Dios.","Porque el SEÑOR da la sabiduría; conocimiento y ciencia brotan de sus labios.","Él reserva su ayuda para la gente íntegra y protege a los de conducta intachable.","Él cuida el sendero de los justos y protege el camino de sus fieles.","Entonces comprenderás la justicia y el derecho, la equidad y todo buen camino;","la sabiduría vendrá a tu corazón, y el conocimiento te endulzará la vida.","La discreción te cuidará, la inteligencia te protegerá.","La sabiduría te librará del camino de los malvados, de los que profieren palabras perversas,","de los que se apartan del camino recto para andar por sendas tenebrosas,","de los que se complacen en hacer lo malo y festejan la perversidad,","de los que andan por caminos torcidos y por sendas extraviadas;","te librará de la mujer ajena, de la extraña de palabras seductoras","que, olvidándose de su pacto con Dios, abandona al compañero de su juventud.","Ciertamente su casa conduce a la muerte; sus sendas llevan al reino de las sombras.","El que se enreda con ella no vuelve jamás, ni alcanza los senderos de la vida.","Así andarás por el camino de los buenos y seguirás la senda de los justos.","Pues los íntegros, los perfectos, habitarán la tierra y permanecerán en ella.","Pero los malvados, los impíos, serán desarraigados y expulsados de la tierra."],
  3: ["Hijo mío, no te olvides de mis enseñanzas; más bien, guarda en tu corazón mis mandamientos.","Porque prolongarán tu vida muchos años y te traerán prosperidad.","Que nunca te abandonen el amor y la verdad: llévalos siempre alrededor de tu cuello y escríbelos en el libro de tu corazón.","Contarás con el favor de Dios y tendrás buena fama[4] entre la gente.","Confía en el SEÑOR de todo corazón, y no en tu propia inteligencia.","Reconócelo en todos tus caminos, y él allanará tus sendas.","No seas sabio en tu propia opinión; más bien, teme al SEÑOR y huye del mal.","Esto infundirá salud a tu cuerpo y fortalecerá tu ser.[5]","Honra al SEÑOR con tus riquezas y con los primeros frutos de tus cosechas.","Así tus graneros se llenarán a reventar y tus bodegas rebosarán de vino nuevo.","Hijo mío, no desprecies la disciplina del SEÑOR, ni te ofendas por sus reprensiones.","Porque el SEÑOR disciplina a los que ama, como corrige un padre a su hijo querido.","Dichoso el que halla sabiduría, el que adquiere inteligencia.","Porque ella es de más provecho que la plata y rinde más ganancias que el oro.","Es más valiosa que las piedras preciosas: ¡ni lo más deseable se le puede comparar!","Con la mano derecha ofrece larga vida; con la izquierda, honor y riquezas.","Sus caminos son placenteros y en sus senderos hay paz.","Ella es árbol de vida para quienes la abrazan; ¡dichosos los que la retienen!","Con sabiduría afirmó el SEÑOR la tierra, con inteligencia estableció los cielos.","Por su conocimiento se separaron las aguas, y las nubes dejaron caer su rocío.","Hijo mío, conserva el buen juicio; no pierdas de vista la discreción.","Te serán fuente de vida, te adornarán como un collar.","Podrás recorrer tranquilo tu camino, y tus pies no tropezarán.","Al acostarte, no tendrás temor alguno; te acostarás y dormirás tranquilo.","No temerás ningún desastre repentino, ni la desgracia que sobreviene a los impíos.","Porque el SEÑOR estará siempre a tu lado y te librará de caer en la trampa.","No niegues un favor a quien te lo pida si en tu mano está el otorgarlo.","Nunca digas a tu prójimo: «Vuelve más tarde; te ayudaré mañana», si hoy tienes con qué ayudarlo.","No urdas el mal contra tu prójimo, contra el que ha puesto en ti su confianza.","No entres en pleito con nadie que no te haya hecho ningún daño.","No envidies a los violentos, ni optes por andar en sus caminos.","Porque el SEÑOR aborrece al perverso, pero al íntegro le brinda su amistad.","La maldición del SEÑOR cae sobre la casa del malvado; su bendición, sobre el hogar de los justos.","El SEÑOR se burla de los burlones, pero muestra su favor a los humildes.","Los sabios son dignos de honra, pero los necios solo merecen deshonra."],
  4: ["Escuchen, hijos, la corrección de un padre; dispónganse a adquirir inteligencia.","Yo les brindo buenas enseñanzas, así que no abandonen mi instrucción.","Cuando yo era pequeño y vivía con mi padre, cuando era el niño consentido de mi madre,","mi padre me instruyó de esta manera: «Aférrate de corazón a mis palabras; obedece mis mandamientos, y vivirás.","Adquiere sabiduría, adquiere inteligencia; no olvides mis palabras ni te apartes de ellas.","No abandones nunca a la sabiduría, y ella te protegerá; ámala, y ella te cuidará.","La sabiduría es lo primero. ¡Adquiere sabiduría! Por sobre todas las cosas, adquiere discernimiento.","Estima a la sabiduría, y ella te exaltará; abrázala, y ella te honrará;","te pondrá en la cabeza una hermosa diadema; te obsequiará una bella corona».","Escucha, hijo mío, acoge mis palabras, y los años de tu vida aumentarán.","Yo te guío por el camino de la sabiduría, te dirijo por sendas de rectitud.","Cuando camines, no encontrarás obstáculos; cuando corras, no tropezarás.","Aférrate a la instrucción, no la dejes escapar; cuídala bien, que ella es tu vida.","No sigas la senda de los perversos ni vayas por el camino de los malvados.","¡Evita ese camino! ¡No pases por él! ¡Aléjate de allí, y sigue de largo!","Los malvados no duermen si no hacen lo malo; pierden el sueño si no hacen que alguien caiga.","Su pan es la maldad; su vino, la violencia.","La senda de los justos se asemeja a los primeros albores de la aurora: su esplendor va en aumento hasta que el día alcanza su plenitud.","Pero el camino de los malvados es como la más densa oscuridad; ¡ni siquiera saben con qué tropiezan!","Hijo mío, atiende a mis consejos; escucha atentamente lo que digo.","No pierdas de vista mis palabras; guárdalas muy dentro de tu corazón.","Ellas dan vida a quienes las hallan; son la salud del cuerpo.","Por sobre todas las cosas cuida tu corazón, porque de él mana la vida.","Aleja de tu boca la perversidad; aparta de tus labios las palabras corruptas.","Pon la mirada en lo que tienes delante; fija la vista en lo que está frente a ti.","Endereza las sendas por donde andas; allana todos tus caminos.","No te desvíes ni a diestra ni a siniestra; apártate de la maldad."],
  5: ["Hijo mío, pon atención a mi sabiduría y presta oído a mi buen juicio,","para que al hablar mantengas la discreción y retengas el conocimiento.","De los labios de la adúltera fluye miel; su lengua es más suave que el aceite.","Pero al fin resulta más amarga que la hiel y más cortante que una espada de dos filos.","Sus pies descienden hasta la muerte; sus pasos van derecho al sepulcro.","No toma ella en cuenta el camino de la vida; sus sendas son torcidas, y ella no lo reconoce.[6]","Pues bien, hijo mío, préstame atención y no te apartes de mis palabras.","Aléjate de la adúltera; no te acerques a la puerta de su casa,","para que no entregues a otros tu vigor, ni tus años a gente cruel;","para que no sacies con tu fuerza a gente extraña, ni vayan a dar en casa ajena tus esfuerzos.","Porque al final acabarás por llorar, cuando todo tu ser[7] se haya consumido.","Y dirás: «¡Cómo pude aborrecer la corrección! ¡Cómo pudo mi corazón despreciar la disciplina!","No atendí a la voz de mis maestros, ni presté oído a mis instructores.","Ahora estoy al borde de la ruina, en medio de toda la comunidad».","Bebe el agua de tu propio pozo, el agua que fluye de tu propio manantial.","¿Habrán de derramarse tus fuentes por las calles y tus corrientes de aguas por las plazas públicas?","Son tuyas, solamente tuyas, y no para que las compartas con extraños.","¡Bendita sea tu fuente! ¡Goza con la esposa de tu juventud!","Es una gacela amorosa, es una cervatilla encantadora. ¡Que sus pechos te satisfagan siempre! ¡Que su amor te cautive todo el tiempo!","¿Por qué, hijo mío, dejarte cautivar por una adúltera? ¿Por qué abrazarte al pecho de la mujer ajena?","Nuestros caminos están a la vista del SEÑOR; él examina todas nuestras sendas.","Al malvado lo atrapan sus malas obras; las cuerdas de su pecado lo aprisionan.","Morirá por su falta de disciplina; perecerá por su gran insensatez."],
  6: ["Hijo mío, si has salido fiador de tu vecino, si has hecho tratos para responder por otro,","si te has comprometido verbalmente, enredándote con tus propias palabras,","entonces has caído en manos de tu prójimo. Si quieres librarte, hijo mío, este es el camino: Ve corriendo y humíllate ante él; procura deshacer tu compromiso.","No permitas que se duerman tus ojos; no dejes que tus párpados se cierren.","Líbrate, como se libra del cazador[8] la gacela, como se libra de la trampa[9] el ave.","¡Anda, perezoso, fíjate en la hormiga! ¡Fíjate en lo que hace, y adquiere sabiduría!","No tiene quien la mande, ni quien la vigile ni gobierne;","con todo, en el verano almacena provisiones y durante la cosecha recoge alimentos.","Perezoso, ¿cuánto tiempo más seguirás acostado? ¿Cuándo despertarás de tu sueño?","Un corto sueño, una breve siesta, un pequeño descanso, cruzado de brazos…","¡y te asaltará la pobreza como un bandido, y la escasez como un hombre armado![10]","El bribón y sinvergüenza, el vagabundo de boca corrupta,","hace guiños con los ojos, y señas con los pies y con los dedos.","El malvado trama el mal en su mente, y siempre anda provocando disensiones.","Por eso le sobrevendrá la ruina; ¡de repente será destruido, y no podrá evitarlo!","Hay seis cosas que el SEÑOR aborrece, y siete que le son detestables:","los ojos que se enaltecen, la lengua que miente, las manos que derraman sangre inocente,","el corazón que hace planes perversos, los pies que corren a hacer lo malo,","el falso testigo que esparce mentiras, y el que siembra discordia entre hermanos.","Hijo mío, obedece el mandamiento de tu padre y no abandones la enseñanza de tu madre.","Grábatelos en el corazón; cuélgatelos al cuello.","Cuando camines, te servirán de guía; cuando duermas, vigilarán tu sueño; cuando despiertes, hablarán contigo.","El mandamiento es una lámpara, la enseñanza es una luz y la disciplina es el camino a la vida.","Te protegerán de la mujer malvada, de la mujer ajena y de su lengua seductora.","No abrigues en tu corazón deseos por su belleza, ni te dejes cautivar por sus ojos,","pues la ramera va tras un pedazo de pan, pero la mujer de otro hombre busca tu propia vida.[11]","¿Puede alguien echarse brasas en el pecho sin quemarse la ropa?","¿Puede alguien caminar sobre las brasas sin quemarse los pies?","Pues tampoco quien se acuesta con la mujer ajena puede tocarla y quedar impune.","No se desprecia al ladrón que roba para mitigar su hambre;","pero si lo atrapan, deberá devolver siete tantos lo robado, aun cuando eso le cueste todas sus posesiones.","Pero al que comete adulterio le faltan sesos; el que así actúa se destruye a sí mismo.","No sacará más que golpes y vergüenzas, y no podrá borrar su oprobio.","Porque los celos desatan la furia del esposo, y este no perdonará en el día de la venganza.","No aceptará nada en desagravio, ni se contentará con muchos regalos."],
  7: ["Hijo mío, pon en práctica[12] mis palabras y atesora mis mandamientos.","Cumple con mis mandatos, y vivirás; cuida mis enseñanzas como a la niña de tus ojos.","Llévalos atados en los dedos; anótalos en la tablilla de tu corazón.","Di a la sabiduría: «Tú eres mi hermana», y a la inteligencia: «Eres de mi sangre».","Ellas te librarán de la mujer ajena, de la adúltera y de sus palabras seductoras.","Desde la ventana de mi casa miré a través de la celosía.","Me puse a ver a los inexpertos, y entre los jóvenes observé a uno de ellos falto de juicio.[13]","Cruzó la calle, llegó a la esquina, y se encaminó hacia la casa de esa mujer.","Caía la tarde. Llegaba el día a su fin. Avanzaban las sombras de la noche.","De pronto la mujer salió a su encuentro, con toda la apariencia de una prostituta y con solapadas intenciones.","(Como es escandalosa y descarada, nunca hallan sus pies reposo en su casa.","Unas veces por las calles, otras veces por las plazas, siempre está al acecho en cada esquina).","Se prendió de su cuello, lo besó, y con todo descaro le dijo:","«Tengo en mi casa sacrificios de comunión, pues hoy he cumplido mis votos.","Por eso he venido a tu encuentro; te buscaba, ¡y ya te he encontrado!","Sobre la cama he tendido multicolores linos egipcios.","He perfumado mi lecho con aroma de mirra, áloe y canela.","Ven, bebamos hasta el fondo la copa del amor; ¡disfrutemos del amor hasta el amanecer!","Mi esposo no está en casa, pues ha emprendido un largo viaje.","Se ha llevado consigo la bolsa del dinero, y no regresará hasta el día de luna llena».","Con palabras persuasivas lo convenció; con lisonjas de sus labios lo sedujo.","Y él en seguida fue tras ella, como el buey que va camino al matadero; como el ciervo[14] que cae en la trampa,[15]","hasta que una flecha le abre las entrañas; como el ave que se lanza contra la red, sin saber que en ello le va la vida.","Así que, hijo mío, escúchame; presta[16] atención a mis palabras.","No desvíes tu corazón hacia sus sendas, ni te extravíes por sus caminos,","pues muchos han muerto por su causa; sus víctimas han sido innumerables.","Su casa lleva derecho al sepulcro; ¡conduce al reino de la muerte!"],
  8: ["¿Acaso no está llamando la sabiduría? ¿No está elevando su voz la inteligencia?","Toma su puesto en las alturas, a la vera del camino y en las encrucijadas.","Junto a las puertas que dan a la ciudad, a la entrada misma, grita a voz en cuello:","«A ustedes los hombres, los estoy llamando; dirijo mi voz a toda la humanidad.","Ustedes los inexpertos, ¡adquieran prudencia! Ustedes los necios, ¡obtengan discernimiento!","Escúchenme, que diré cosas importantes; mis labios hablarán lo correcto.","Mi boca expresará la verdad, pues mis labios detestan la mentira.","Las palabras de mi boca son todas justas; no hay en ellas maldad ni doblez.","Son claras para los entendidos, e irreprochables para los sabios.","Opten por mi instrucción, no por la plata; por el conocimiento, no por el oro refinado.","Vale más la sabiduría que las piedras preciosas, y ni lo más deseable se le compara.","»Yo, la sabiduría, convivo con la prudencia y poseo conocimiento y discreción.","Quien teme al SEÑOR aborrece lo malo; yo aborrezco el orgullo y la arrogancia, la mala conducta y el lenguaje perverso.","Míos son el consejo y el buen juicio; míos son el entendimiento y el poder.","Por mí reinan los reyes y promulgan leyes justas los gobernantes.","Por mí gobiernan los príncipes y todos los nobles que rigen la tierra.[17]","A los que me aman, les correspondo; a los que me buscan, me doy a conocer.","Conmigo están las riquezas y la honra, la prosperidad[18] y los bienes duraderos.","Mi fruto es mejor que el oro fino; mi cosecha sobrepasa a la plata refinada.","Voy por el camino de la rectitud, por los senderos de la justicia,","enriqueciendo a los que me aman y acrecentando sus tesoros.","»El SEÑOR me dio la vida[19] como primicia de sus obras,[20] mucho antes de sus obras de antaño.","Fui establecida desde la eternidad, desde antes que existiera el mundo.","No existían los grandes mares cuando yo nací; no había entonces manantiales de abundantes aguas.","Nací antes que fueran formadas las colinas, antes que se cimentaran las montañas,","antes que él creara la tierra y sus paisajes y el polvo primordial con que hizo el mundo.","Cuando Dios cimentó la bóveda celeste y trazó el horizonte sobre las aguas, allí estaba yo presente.","Cuando estableció las nubes en los cielos y reforzó las fuentes del mar profundo;","cuando señaló los límites del mar, para que las aguas obedecieran su mandato; cuando plantó los fundamentos de la tierra,","allí estaba yo, afirmando su obra. Día tras día me llenaba yo de alegría, siempre disfrutaba de estar en su presencia;","me regocijaba en el mundo que él creó; ¡en el género humano me deleitaba!","»Y ahora, hijos míos, escúchenme: dichosos los que van por[21] mis caminos.","Atiendan a mi instrucción, y sean sabios; no la descuiden.","Dichosos los que me escuchan y a mis puertas están atentos cada día, esperando a la entrada de mi casa.","En verdad, quien me encuentra halla la vida y recibe el favor del SEÑOR.","Quien me rechaza se perjudica a sí mismo; quien me aborrece, ama la muerte»."],
  9: ["La sabiduría construyó su casa y labró sus siete pilares.","Preparó un banquete, mezcló su vino y tendió la mesa.","Envió a sus doncellas, y ahora clama desde lo más alto de la ciudad.","«¡Vengan conmigo los inexpertos! —dice a los faltos de juicio—.","Vengan, disfruten de mi pan y beban del vino que he mezclado.","Dejen su insensatez, y vivirán; andarán por el camino del discernimiento.","»El que corrige al burlón se gana que lo insulten; el que reprende al malvado se gana su desprecio.","No reprendas al insolente, no sea que acabe por odiarte; reprende al sabio, y te amará.","Instruye al sabio, y se hará más sabio; enseña al justo, y aumentará su saber.","»El comienzo de la sabiduría es el temor del SEÑOR; conocer al Santo[22] es tener discernimiento.","Por mí aumentarán tus días; muchos años de vida te serán añadidos.","Si eres sabio, tu premio será tu sabiduría; si eres insolente, solo tú lo sufrirás».","La mujer necia es escandalosa, frívola y desvergonzada.","Se sienta a las puertas de su casa, sienta sus reales en lo más alto de la ciudad,","y llama a los que van por el camino, a los que no se apartan de su senda.","«¡Vengan conmigo, inexpertos! —dice a los faltos de juicio—.","¡Las aguas robadas saben a gloria! ¡El pan sabe a miel si se come a escondidas!»","Pero estos ignoran que allí está la muerte, que sus invitados caen al fondo de la fosa."],
  10: ["Proverbios de Salomón: El hijo sabio es la alegría de su padre; el hijo necio es el pesar de su madre.","Las riquezas mal habidas no sirven de nada, pero la justicia libra de la muerte.","El SEÑOR no deja sin comer al justo, pero frustra la avidez de los malvados.","Las manos ociosas conducen a la pobreza; las manos hábiles atraen riquezas.","El hijo prevenido se abastece en el verano, pero el sinvergüenza duerme en tiempo de cosecha.","El justo se ve coronado de bendiciones, pero la boca del malvado encubre violencia.","La memoria de los justos es una bendición, pero la fama de los malvados será pasto de los gusanos.","El de sabio corazón acata las órdenes, pero el necio y rezongón va camino al desastre.","Quien se conduce con integridad anda seguro; quien anda en malos pasos será descubierto.","Quien guiña el ojo con malicia provoca pesar; el necio y rezongón va camino al desastre.","Fuente de vida es la boca del justo, pero la boca del malvado encubre violencia.","El odio es motivo de disensiones, pero el amor cubre todas las faltas.","En los labios del prudente hay sabiduría; en la espalda del falto de juicio, solo garrotazos.","El que es sabio atesora el conocimiento, pero la boca del necio es un peligro inminente.","La riqueza del rico es su baluarte; la pobreza del pobre es su ruina.","El salario del justo es la vida; la ganancia del malvado es el pecado.","El que atiende a la corrección va camino a la vida; el que la rechaza se pierde.","El de labios mentirosos disimula su odio, y el que propaga calumnias es un necio.","El que mucho habla, mucho yerra; el que es sabio refrena su lengua.","Plata refinada es la lengua del justo; el corazón del malvado no vale nada.","Los labios del justo orientan a muchos; los necios mueren por falta de juicio.","La bendición del SEÑOR trae riquezas, y nada se gana con preocuparse.","El necio se divierte con su mala conducta, pero el sabio se recrea con la sabiduría.","Lo que el malvado teme, eso le ocurre; lo que el justo desea, eso recibe.","Pasa la tormenta y desaparece el malvado, pero el justo permanece firme para siempre.","Como vinagre a los dientes y humo a los ojos es el perezoso para quienes lo emplean.","El temor del SEÑOR prolonga la vida, pero los años del malvado se acortan.","El futuro de los justos es halagüeño; la esperanza de los malvados se desvanece.","El camino del SEÑOR es refugio de los justos y ruina de los malhechores.","Los justos no tropezarán jamás; los malvados no habitarán la tierra.","La boca del justo profiere sabiduría, pero la lengua perversa será cercenada.","Los labios del justo destilan[23] bondad; de la boca del malvado brota perversidad."],
  11: ["El SEÑOR aborrece las balanzas adulteradas, pero aprueba las pesas exactas.","Con el orgullo viene el oprobio; con la humildad, la sabiduría.","A los justos los guía su integridad; a los falsos los destruye su hipocresía.","En el día de la ira de nada sirve ser rico, pero la justicia libra de la muerte.","La justicia endereza el camino de los íntegros, pero la maldad hace caer a los impíos.","La justicia libra a los justos, pero la codicia atrapa a los falsos.","Muere el malvado, y con él su esperanza; muere también su ilusión de poder.","El justo se salva de la calamidad, pero la desgracia le sobreviene al malvado.","Con la boca el impío destruye a su prójimo, pero los justos se libran por el conocimiento.","Cuando el justo prospera, la ciudad se alegra; cuando el malvado perece, hay gran regocijo.","La bendición de los justos enaltece a la ciudad, pero la boca de los malvados la destruye.","El falto de juicio desprecia a su prójimo, pero el entendido refrena su lengua.","La gente chismosa revela los secretos; la gente confiable es discreta.","Sin dirección, la nación fracasa; el éxito depende de los muchos consejeros.","El fiador de un extraño saldrá perjudicado; negarse a dar fianza[24] es vivir en paz.","La mujer bondadosa se gana el respeto; los hombres violentos solo ganan riquezas.","El que es bondadoso se beneficia a sí mismo; el que es cruel, a sí mismo se perjudica.","El malvado obtiene ganancias ilusorias; el que siembra justicia asegura su ganancia.","El que es justo obtiene la vida; el que persigue el mal se encamina a la muerte.","El SEÑOR aborrece a los de corazón perverso, pero se complace en los que viven con rectitud.","Una cosa es segura:[25] Los malvados no quedarán impunes, pero los justos saldrán bien librados.","Como argolla de oro en hocico de cerdo es la mujer bella pero indiscreta.","Los deseos de los justos terminan bien; la esperanza de los malvados termina mal.[26]","Unos dan a manos llenas, y reciben más de lo que dan; otros ni sus deudas pagan, y acaban en la miseria.","El que es generoso prospera; el que reanima será reanimado.","La gente maldice al que acapara el trigo, pero colma de bendiciones al que gustoso lo vende.","El que madruga para el bien, halla buena voluntad; el que anda tras el mal, por el mal será alcanzado.","El que confía en sus riquezas se marchita, pero el justo se renueva como el follaje.","El que perturba su casa no hereda más que el viento, y el necio termina sirviendo al sabio.","El fruto de la justicia[27] es árbol de vida, pero el que arrebata vidas es violento.[28]","Si los justos reciben su pago aquí en la tierra, ¡cuánto más los impíos y los pecadores!"],
  12: ["El que ama la disciplina ama el conocimiento, pero el que la aborrece es un necio.","El hombre bueno recibe el favor del SEÑOR, pero el intrigante recibe su condena.","Nadie puede afirmarse por medio de la maldad; solo queda firme la raíz de los justos.","La mujer ejemplar[29] es corona de su esposo; la desvergonzada es carcoma en los huesos.","En los planes del justo hay justicia, pero en los consejos del malvado hay engaño.","Las palabras del malvado son insidias de muerte, pero la boca de los justos los pone a salvo.","Los malvados se derrumban y dejan de existir, pero los hijos de los justos permanecen.","Al hombre se le alaba según su sabiduría, pero al de mal corazón se le desprecia.","Vale más un Don Nadie con criado que un Don Alguien sin pan.","El justo atiende a las necesidades de su bestia, pero el malvado es de mala entraña.","El que labra su tierra tendrá abundante comida, pero el que sueña despierto[30] es un imprudente.","Los malos deseos son la trampa[31] de los malvados, pero la raíz de los justos prospera.","En el pecado de sus labios se enreda el malvado, pero el justo sale del aprieto.","Cada uno se sacia[32] del fruto de sus labios, y de la obra de sus manos recibe su recompensa.","Al necio le parece bien lo que emprende, pero el sabio escucha el consejo.","El necio muestra en seguida su enojo, pero el prudente pasa por alto el insulto.","El testigo verdadero declara lo que es justo, pero el testigo falso declara falsedades.","El charlatán hiere con la lengua como con una espada, pero la lengua del sabio brinda alivio.","Los labios sinceros permanecen para siempre, pero la lengua mentirosa dura solo un instante.","En los que fraguan el mal habita el engaño, pero hay gozo para los que promueven la paz.","Al justo no le sobrevendrá ningún daño, pero al malvado lo cubrirá la desgracia.","El SEÑOR aborrece a los de labios mentirosos, pero se complace en los que actúan con lealtad.","El hombre prudente no muestra lo que sabe, pero el corazón de los necios proclama su necedad.","El de manos diligentes gobernará; pero el perezoso será subyugado.","La angustia abate el corazón del hombre, pero una palabra amable lo alegra.","El justo es guía de su prójimo,[33] pero el camino del malvado lleva a la perdición.","El perezoso no atrapa presa,[34] pero el diligente ya posee una gran riqueza.","En el camino de la justicia se halla la vida; por ese camino se evita la muerte."],
  13: ["El hijo sabio atiende a[35] la corrección de su padre, pero el insolente no hace caso a la reprensión.","Quien habla el bien, del bien se nutre, pero el infiel padece hambre de violencia.","El que refrena su lengua protege su vida, pero el ligero de labios provoca su ruina.","El perezoso ambiciona, y nada consigue; el diligente ve cumplidos sus deseos.","El justo aborrece la mentira; el malvado acarrea vergüenza y deshonra.","La justicia protege al que anda en integridad, pero la maldad arruina al pecador.","Hay quien pretende ser rico, y no tiene nada; hay quien parece ser pobre, y todo lo tiene.","Con su riqueza el rico pone a salvo su vida, pero al pobre no hay ni quien lo amenace.","La luz de los justos brilla radiante,[36] pero los malvados son como lámpara apagada.","El orgullo solo genera contiendas, pero la sabiduría está con quienes oyen consejos.","El dinero mal habido pronto se acaba; quien ahorra, poco a poco se enriquece.","La esperanza frustrada aflige al corazón; el deseo cumplido es un árbol de vida.","Quien se burla de la instrucción tendrá su merecido; quien respeta el mandamiento tendrá su recompensa.","La enseñanza de los sabios es fuente de vida, y libera de los lazos de la muerte.","El buen juicio redunda en aprecio, pero el camino del infiel no cambia.","El prudente actúa con cordura, pero el necio se jacta de su necedad.","El mensajero malvado se mete en problemas; el enviado confiable aporta la solución.","El que desprecia la disciplina sufre pobreza y deshonra; el que atiende la corrección recibe grandes honores.","El deseo cumplido endulza el alma, pero el necio detesta alejarse del mal.","El que con sabios anda, sabio se vuelve; el que con necios se junta, saldrá mal parado.","Al pecador lo persigue el mal, y al justo lo recompensa el bien.","El hombre de bien deja herencia a sus nietos; las riquezas del pecador se quedan para los justos.","En el campo del pobre hay abundante comida, pero esta se pierde donde hay injusticia.","No corregir al hijo es no quererlo; amarlo es disciplinarlo.","El justo come hasta quedar saciado, pero el malvado se queda con hambre."],
  14: ["La mujer sabia edifica su casa; la necia, con sus manos la destruye.","El que va por buen camino teme al SEÑOR; el que va por mal camino lo desprecia.","De la boca del necio brota arrogancia; los labios del sabio son su propia protección.","Donde no hay bueyes el granero está vacío; con la fuerza del buey aumenta la cosecha.","El testigo verdadero jamás engaña; el testigo falso propaga mentiras.","El insolente busca sabiduría y no la halla; para el entendido, el conocimiento es cosa fácil.","Manténte a distancia del necio, pues en sus labios no hallarás conocimiento.","La sabiduría del prudente es discernir sus caminos, pero al necio lo engaña su propia necedad.","Los necios hacen mofa de sus propias faltas, pero los íntegros cuentan con el favor de Dios.","Cada corazón conoce sus propias amarguras, y ningún extraño comparte su alegría.","La casa del malvado será destruida, pero la morada del justo prosperará.","Hay caminos que al hombre le parecen rectos, pero que acaban por ser caminos de muerte.","También de reírse duele el corazón, y hay alegrías que acaban en tristeza.","El inconstante recibirá todo el pago de su inconstancia; el hombre bueno, el premio de sus acciones.","El ingenuo cree todo lo que le dicen; el prudente se fija por dónde va.","El sabio teme al SEÑOR y se aparta del mal, pero el necio es arrogante y se pasa de confiado.","El iracundo comete locuras, pero el prudente sabe aguantar.[37]","Herencia de los inexpertos es la necedad; corona de los prudentes, el conocimiento.","Los malvados se postrarán ante los buenos; los impíos, ante el tribunal[38] de los justos.","Al pobre hasta sus amigos lo aborrecen, pero son muchos los que aman al rico.","Es un pecado despreciar al prójimo; ¡dichoso el que se compadece de los pobres!","Pierden el camino los que maquinan el mal, pero hallan amor y verdad los que hacen el bien.","Todo esfuerzo tiene su recompensa, pero quedarse solo en palabras lleva a la pobreza.","La corona del sabio es su sabiduría;[39] la de los necios, su necedad.","El testigo veraz libra de la muerte, pero el testigo falso miente.","El temor del SEÑOR es un baluarte seguro que sirve de refugio a los hijos.","El temor del SEÑOR es fuente de vida, y aleja al hombre de las redes de la muerte.","Gloria del rey es gobernar a muchos; un príncipe sin súbditos está arruinado.","El que es paciente muestra gran discernimiento; el que es agresivo muestra mucha insensatez.","El corazón tranquilo da vida al cuerpo, pero la envidia corroe los huesos.","El que oprime al pobre ofende a su creador, pero honra a Dios quien se apiada del necesitado.","El malvado cae por su propia maldad; el justo halla refugio en su integridad.[40]","En el corazón de los sabios mora la sabiduría, pero los necios ni siquiera la conocen.[41]","La justicia enaltece a una nación, pero el pecado deshonra a todos los pueblos.","El rey favorece al siervo inteligente, pero descarga su ira sobre el sinvergüenza."],
  15: ["La respuesta amable calma el enojo, pero la agresiva echa leña al fuego.","La lengua de los sabios destila conocimiento;[42] la boca de los necios escupe necedades.","Los ojos del SEÑOR están en todo lugar, vigilando a los buenos y a los malos.","La lengua que brinda alivio[43] es árbol de vida; la lengua insidiosa deprime el espíritu.","El necio desdeña la corrección de su padre; el que la acepta demuestra prudencia.","En la casa del justo hay gran abundancia; en las ganancias del malvado, grandes problemas.","Los labios de los sabios esparcen conocimiento; el corazón de los necios ni piensa en ello.","El SEÑOR aborrece las ofrendas de los malvados, pero se complace en la oración de los justos.","El SEÑOR aborrece el camino de los malvados, pero ama a quienes siguen la justicia.","Para el descarriado, disciplina severa; para el que aborrece la corrección, la muerte.","Si ante el SEÑOR están el sepulcro y la muerte, ¡cuánto más el corazón humano!","Al insolente no le gusta que lo corrijan, ni busca la compañía de los sabios.","El corazón alegre se refleja en el rostro, el corazón dolido deprime el espíritu.","El corazón entendido va tras el conocimiento; la boca de los necios se nutre de tonterías.","Para el afligido todos los días son malos; para el que es feliz todos son de fiesta.","Más vale tener poco, con temor del SEÑOR, que muchas riquezas con grandes angustias.","Más vale comer verduras sazonadas con amor que un festín de carne[44] sazonada con odio.","El que es iracundo provoca contiendas; el que es paciente las apacigua.","El camino del perezoso está plagado de espinas, pero la senda del justo es como una calzada.","El hijo sabio alegra a su padre; el hijo necio menosprecia a su madre.","Al necio le divierte su falta de juicio; el entendido endereza sus propios pasos.","Cuando falta el consejo, fracasan los planes; cuando abunda el consejo, prosperan.","Es muy grato dar la respuesta adecuada, y más grato aún cuando es oportuna.","El sabio sube por el sendero de vida, para librarse de caer en el sepulcro.","El SEÑOR derriba la casa de los soberbios, pero mantiene intactos los linderos de las viudas.","El SEÑOR aborrece los planes de los malvados, pero se complace en las palabras puras.","El ambicioso acarrea mal sobre su familia; el que aborrece el soborno vivirá.","El corazón del justo medita sus respuestas, pero la boca del malvado rebosa de maldad.","El SEÑOR se mantiene lejos de los impíos, pero escucha las oraciones de los justos.","Una mirada radiante alegra el corazón, y las buenas noticias renuevan las fuerzas.[45]","El que atiende a la crítica edificante habitará entre los sabios.","El que rechaza la corrección se desprecia a sí mismo; el que la atiende gana entendimiento.","El temor del SEÑOR imparte sabiduría; la humildad precede a la honra."],
  16: ["El hombre propone y Dios[46] dispone.","A cada uno le parece correcto su proceder,[47] pero el SEÑOR juzga los motivos.","Pon en manos del SEÑOR todas tus obras, y tus proyectos se cumplirán.","Toda obra del SEÑOR tiene un propósito; ¡hasta el malvado fue hecho para el día del desastre!","El SEÑOR aborrece a los arrogantes. Una cosa es segura: no quedarán impunes.","Con amor y verdad se perdona el pecado, y con temor del SEÑOR se evita el mal.","Cuando el SEÑOR aprueba la conducta de un hombre, hasta con sus enemigos lo reconcilia.","Más vale tener poco con justicia que ganar mucho con injusticia.","El corazón del hombre traza su rumbo, pero sus pasos los dirige el SEÑOR.","La sentencia[48] está en labios del rey; en el veredicto que emite no hay error.","Las pesas y las balanzas justas son del SEÑOR; todas las medidas son hechura suya.","El rey detesta las malas acciones, porque el trono se afirma en la justicia.","El rey se complace en los labios honestos; aprecia a quien habla con la verdad.","La ira del rey es presagio de muerte, pero el sabio sabe apaciguarla.","El rostro radiante del rey es signo de vida; su favor es como lluvia en primavera.","Más vale adquirir sabiduría que oro; más vale adquirir inteligencia que plata.","El camino del hombre recto evita el mal; el que quiere salvar su vida se fija por dónde va.","Al orgullo le sigue la destrucción; a la altanería, el fracaso.","Vale más humillarse con los oprimidos que compartir el botín con los orgullosos.","El que atiende a la palabra prospera. ¡Dichoso el que confía en el SEÑOR!","Al sabio de corazón se le llama inteligente; los labios convincentes promueven el saber.","Fuente de vida es la prudencia para quien la posee; el castigo de los necios es su propia necedad.","El sabio de corazón controla su boca; con sus labios promueve el saber.","Panal de miel son las palabras amables: endulzan la vida y dan salud al cuerpo.[49]","Hay caminos que al hombre le parecen rectos, pero que acaban por ser caminos de muerte.","Al que trabaja, el hambre lo obliga a trabajar, pues su propio apetito lo estimula.","El perverso hace[50] planes malvados; en sus labios hay un fuego devorador.","El perverso provoca contiendas, y el chismoso divide a los buenos amigos.","El violento engaña a su prójimo y lo lleva por mal camino.","El que guiña el ojo trama algo perverso; el que aprieta los labios ya lo ha cometido.","Las canas son una honrosa corona que se obtiene en el camino de la justicia.","Más vale ser paciente que valiente; más vale el dominio propio que conquistar ciudades.","Las suertes se echan sobre la mesa,[51] pero el veredicto proviene del SEÑOR."],
  17: ["Más vale comer pan duro donde hay concordia que hacer banquete[52] donde hay discordia.","El siervo sabio gobernará al hijo sinvergüenza, y compartirá la herencia con los otros hermanos.","En el crisol se prueba la plata y en el horno se prueba el oro, pero al corazón lo prueba el SEÑOR.","El malvado hace caso a los labios impíos, y el mentiroso presta oído a la lengua maliciosa.","El que se burla del pobre ofende a su creador; el que se alegra de verlo en la ruina no quedará sin castigo.","La corona del anciano son sus nietos; el orgullo de los hijos son sus padres.","No va bien con los necios el lenguaje refinado, ni con los gobernantes, la mentira.","Vara[53] mágica es el soborno para quien lo ofrece, pues todo lo que emprende lo consigue.","El que perdona la ofensa cultiva el amor; el que insiste en la ofensa divide a los amigos.","Cala más un regaño en el hombre prudente que cien latigazos en el obstinado.","El revoltoso siempre anda buscando camorra, pero se las verá con un mensajero cruel.","Más vale toparse con una osa a la que le quitaron los cachorros que con un necio empecinado en su necedad.","El mal nunca se apartará de la familia de aquel que devuelve mal por bien.","Iniciar una pelea es romper una represa; vale más retirarse que comenzarla.","Absolver al culpable y condenar al inocente son dos cosas que el SEÑOR aborrece.","¿De qué le sirve al necio poseer dinero? ¿Podrá adquirir sabiduría si le faltan sesos?[54]","En todo tiempo ama el amigo; para ayudar en la adversidad nació el hermano.","El que es imprudente se compromete por otros, y sale fiador de su prójimo.","Al que le gusta pecar, le gusta pelear; el que abre mucho la boca busca que se la rompan.[55]","El de corazón perverso jamás prospera; el de lengua engañosa caerá en desgracia.","Engendrar a un hijo necio es causa de pesar; ser padre de un necio no es ninguna alegría.","Gran remedio es el corazón alegre, pero el ánimo decaído seca los huesos.","El malvado acepta soborno en secreto, con lo que tuerce el curso de la justicia.","La meta del prudente es la sabiduría; el necio divaga contemplando vanos horizontes.[56]","El hijo necio irrita a su padre, y causa amargura a su madre.","No está bien castigar al inocente, ni azotar por su rectitud a gente honorable.","El que es entendido refrena sus palabras; el que es prudente controla sus impulsos.","Hasta un necio pasa por sabio si guarda silencio; se le considera prudente si cierra la boca."],
  18: ["El egoísta busca su propio bien; contra todo sano juicio se rebela.","Al necio no le complace el discernimiento; tan solo hace alarde de su propia opinión.","Con la maldad viene el desprecio, y con la vergüenza llega el oprobio.","Las palabras del hombre son aguas profundas, arroyo de aguas vivas, fuente de sabiduría.","No está bien declarar inocente al[57] malvado y dejar de lado los derechos del justo.","Los labios del necio son causa de contienda; su boca incita a la riña.","La boca del necio es su perdición; sus labios son para él una trampa mortal.","Los chismes son deliciosos manjares; penetran hasta lo más íntimo del ser.","El que es negligente en su trabajo confraterniza con el que es destructivo.","Torre inexpugnable es el nombre del SEÑOR; a ella corren los justos y se ponen a salvo.","Ciudad amurallada es la riqueza para el rico, y este cree que sus muros son inexpugnables.","Al fracaso lo precede la soberbia humana; a los honores los precede la humildad.","Es necio y vergonzoso responder antes de escuchar.","En la enfermedad, el ánimo levanta al enfermo; ¿pero quién podrá levantar al abatido?","El corazón prudente adquiere conocimiento; los oídos de los sabios procuran hallarlo.","Con regalos se abren todas las puertas y se llega a la presencia de gente importante.","El primero en presentar su caso parece inocente, hasta que llega la otra parte y lo refuta.","El echar suertes pone fin a los litigios y decide entre las partes en pugna.","Más resiste el hermano ofendido que una ciudad amurallada; los litigios son como cerrojos de ciudadela.","Cada uno se llena con lo que dice y se sacia con lo que habla.","En la lengua hay poder de vida y muerte; quienes la aman comerán de su fruto.","Quien halla esposa halla la felicidad: muestras de su favor le ha dado el SEÑOR.","El pobre habla en tono suplicante; el rico responde con aspereza.","Hay amigos[58] que llevan a la ruina, y hay amigos más fieles que un hermano."],
  19: ["Más vale ser pobre e intachable que necio y embustero.","El afán sin conocimiento no vale nada; mucho yerra quien mucho corre.","La necedad del hombre le hace perder el rumbo, y para colmo su corazón se irrita contra el SEÑOR.","Con las riquezas aumentan los amigos, pero al pobre hasta su amigo lo abandona.","El testigo falso no quedará sin castigo; el que esparce mentiras no saldrá bien librado.","Muchos buscan congraciarse con los poderosos; todos son amigos de quienes reparten regalos.","Si al pobre lo aborrecen sus parientes, con más razón lo evitan sus amigos. Aunque los busca suplicante, por ninguna parte los encuentra.[59]","El que adquiere cordura[60] a sí mismo se ama, y el que retiene el discernimiento prospera.","El testigo falso no quedará sin castigo; el que difunde mentiras perecerá.","No va bien con el necio vivir entre lujos, y menos con el esclavo gobernar a los príncipes.","El buen juicio hace al hombre paciente; su gloria es pasar por alto la ofensa.","Rugido de león es la ira del rey; su favor es como rocío sobre el pasto.","El hijo necio es la ruina del padre; la mujer pendenciera es gotera constante.","La casa y el dinero se heredan de los padres, pero la esposa inteligente es un don del SEÑOR.","La pereza conduce al sueño profundo; el holgazán pasará hambre.","El que cumple el mandamiento cumple consigo mismo; el que descuida su conducta morirá.","Servir al pobre es hacerle un préstamo al SEÑOR; Dios pagará esas buenas acciones.","Corrige a tu hijo mientras aún hay esperanza; no te hagas cómplice de su muerte.[61]","El iracundo tendrá que afrontar el castigo; el que intente disuadirlo aumentará su enojo.[62]","Escucha el consejo y acepta la corrección, y llegarás a ser sabio.","El corazón humano genera muchos proyectos, pero al final prevalecen los designios del SEÑOR.","De todo hombre se espera lealtad.[63] Más vale ser pobre que mentiroso.","El temor del SEÑOR conduce a la vida; da un sueño tranquilo y evita los problemas.","El perezoso mete la mano en el plato, pero es incapaz de llevarse el bocado a la boca.","Golpea al insolente, y se hará prudente el inexperto; reprende al entendido, y ganará en conocimiento.","El que roba a su padre y echa a la calle a su madre es un hijo infame y sinvergüenza.","Hijo mío, si dejas de atender a la corrección, te apartarás de las palabras del saber.","El testigo corrupto se burla de la justicia, y la boca del malvado engulle maldad.","El castigo se dispuso para los insolentes, y los azotes para la espalda de los necios."],
  20: ["El vino lleva a la insolencia, y la bebida embriagante al escándalo; ¡nadie bajo sus efectos se comporta sabiamente!","Rugido de león es la furia del rey; quien provoca su enojo se juega la vida.","Honroso es al hombre evitar la contienda, pero no hay necio que no inicie un pleito.","El perezoso no labra la tierra en otoño; en tiempo de cosecha buscará y no hallará.","Los pensamientos humanos son aguas profundas; el que es inteligente los capta fácilmente.","Son muchos los que proclaman su lealtad, ¿pero quién puede hallar a alguien digno de confianza?","Justo es quien lleva una vida sin tacha; ¡dichosos los hijos que sigan su ejemplo![64]","Cuando el rey se sienta en el tribunal, con su sola mirada barre toda maldad.","¿Quién puede afirmar: «Tengo puro el corazón; estoy limpio de pecado»?","Pesas falsas y medidas engañosas: ¡vaya pareja que el SEÑOR detesta!","Por sus hechos el niño deja entrever si su conducta será pura y recta.","Los oídos para oír y los ojos para ver: ¡hermosa pareja que el SEÑOR ha creado!","No te des al sueño, o te quedarás pobre; mantente despierto y tendrás pan de sobra.","«¡No sirve, no sirve!», dice el comprador, pero luego va y se jacta de su compra.","Oro hay, y abundan las piedras preciosas, pero aún más valiosos son los labios del saber.","Toma la prenda del que salga fiador de un extraño; retenla en garantía si la da en favor de desconocidos.","Tal vez sea agradable ganarse el pan con engaños, pero uno acaba con la boca llena de arena.","Afirma tus planes con buenos consejos; entabla el combate con buena estrategia.","El chismoso traiciona la confianza; no te juntes con la gente que habla de más.","Al que maldiga a su padre y a su madre, su lámpara se le apagará en la más densa oscuridad.","La herencia de fácil comienzo no tendrá un final feliz.","Nunca digas: «¡Me vengaré de ese daño!» Confía en el SEÑOR, y él actuará por ti.","El SEÑOR aborrece las pesas falsas y reprueba el uso de medidas engañosas.","Los pasos del hombre los dirige el SEÑOR. ¿Cómo puede el hombre entender su propio camino?","Trampa es consagrar algo sin pensarlo y más tarde reconsiderar lo prometido.","El rey sabio avienta como trigo a los malvados, y los desmenuza con rueda de molino.","El espíritu humano es la lámpara del SEÑOR, pues escudriña lo más recóndito del ser.","La misericordia y la verdad sostienen al rey; su trono se afirma en la misericordia.","La gloria de los jóvenes radica en su fuerza; la honra de los ancianos, en sus canas.","Los golpes y las heridas curan la maldad; los azotes purgan lo más íntimo del ser."],
  21: ["En las manos del SEÑOR el corazón del rey es como un río: sigue el curso que el SEÑOR le ha trazado.","A cada uno le parece correcto su proceder,[65] pero el SEÑOR juzga los corazones.","Practicar la justicia y el derecho lo prefiere el SEÑOR a los sacrificios.","Los ojos altivos, el corazón orgulloso y la lámpara de los malvados son pecado.","Los planes bien pensados: ¡pura ganancia! Los planes apresurados: ¡puro fracaso!","La fortuna amasada por la lengua embustera se esfuma como la niebla y es mortal como una trampa.[66]","La violencia de los malvados los destruirá, porque se niegan a practicar la justicia.","Torcido es el camino del culpable, pero recta la conducta del hombre honrado.","Más vale habitar en un rincón de la azotea que compartir el techo con mujer pendenciera.","El malvado solo piensa en el mal; jamás se compadece de su prójimo.","Cuando se castiga al insolente, aprende[67] el inexperto; cuando se instruye al sabio, el inexperto adquiere conocimiento.","El justo se fija en la casa del malvado, y ve cuando este acaba en la ruina.","Quien cierra sus oídos al clamor del pobre llorará también sin que nadie le responda.","El regalo secreto apacigua el enojo; el obsequio discreto calma la ira violenta.","Cuando se hace justicia, se alegra el justo y tiembla el malhechor.","Quien se aparta de la senda del discernimiento irá a parar entre los muertos.","El que ama el placer se quedará en la pobreza; el que ama el vino y los perfumes jamás será rico.","El malvado pagará por el justo, y el traidor por el hombre intachable.","Más vale habitar en el desierto que con mujer pendenciera y de mal genio.","En casa del sabio abundan las riquezas y el perfume, pero el necio todo lo despilfarra.","El que va tras la justicia y el amor halla vida, prosperidad[68] y honra.","El sabio conquista la ciudad de los valientes y derriba el baluarte en que ellos confiaban.","El que refrena su boca y su lengua se libra de muchas angustias.","Orgulloso y arrogante, y famoso por insolente, es quien se comporta con desmedida soberbia.","La codicia del perezoso lo lleva a la muerte, porque sus manos se niegan a trabajar;","todo el día se lo pasa codiciando, pero el justo da con generosidad.","El sacrificio de los malvados es detestable, y más aún cuando se ofrece con mala intención.","El testigo falso perecerá, y quien le haga caso será destruido[69] para siempre.","El malvado es inflexible en sus decisiones; el justo examina[70] su propia conducta.","De nada sirven ante el SEÑOR la sabiduría, la inteligencia y el consejo.","Se alista al caballo para el día de la batalla, pero la victoria depende del SEÑOR."],
  22: ["Vale más la buena fama que las muchas riquezas, y más que oro y plata, la buena reputación.","El rico y el pobre tienen esto en común: a ambos los ha creado el SEÑOR.","El prudente ve el peligro y lo evita; el inexperto sigue adelante y sufre las consecuencias.","Recompensa de la humildad y del temor del SEÑOR son las riquezas, la honra y la vida.","Espinas y trampas hay en la senda de los impíos, pero el que cuida su vida se aleja de ellas.","Instruye al niño en el camino correcto, y aun en su vejez no lo abandonará.","Los ricos son los amos de los pobres; los deudores son esclavos de sus acreedores.","El que siembra maldad cosecha desgracias; el SEÑOR lo destruirá con el cetro de su ira.[71]","El que es generoso[72] será bendecido, pues comparte su comida con los pobres.","Despide al insolente, y se irá la discordia y cesarán los pleitos y los insultos.","El que ama la pureza de corazón y tiene gracia al hablar tendrá por amigo al rey.","Los ojos del SEÑOR protegen el saber, pero desbaratan las palabras del traidor.","«¡Hay un león allá afuera! —dice el holgazán—. ¡En plena calle me va a hacer pedazos!»","La boca de la adúltera es una fosa profunda; en ella caerá quien esté bajo la ira del SEÑOR.","La necedad es parte del corazón juvenil, pero la vara de la disciplina la corrige.","Oprimir al pobre para enriquecerse, y hacerle regalos al rico, ¡buena manera de empobrecerse!","Presta atención, escucha mis palabras;[73] aplica tu corazón a mi conocimiento.","Grato es retenerlas dentro de ti, y tenerlas todas a flor de labio.","A ti te las enseño en este día, para que pongas tu confianza en el SEÑOR.","¿Acaso no te he escrito treinta[74] dichos que contienen sabios consejos?","Son para enseñarte palabras ciertas y confiables, para que sepas responder bien a quien te pregunte.[75]","No explotes al pobre porque es pobre, ni oprimas en los tribunales[76] a los necesitados;","porque el SEÑOR defenderá su causa, y despojará a quienes los despojen.","No te hagas amigo de gente violenta, ni te juntes con los iracundos,","no sea que aprendas sus malas costumbres y tú mismo caigas en la trampa.","No te comprometas por otros ni salgas fiador de deudas ajenas;","porque, si no tienes con qué pagar, te quitarán hasta la cama en que duermes.","No cambies de lugar los linderos antiguos que establecieron tus antepasados.","¿Has visto a alguien diligente en su trabajo? Se codeará con reyes, y nunca será un don nadie."],
  23: ["Cuando te sientes a comer con un gobernante, fíjate bien en lo que[77] tienes ante ti.","Si eres dado a la glotonería, domina tu apetito.[78]","No codicies sus manjares, pues tal comida no es más que un engaño.","No te afanes acumulando riquezas; no te obsesiones con ellas.","¿Acaso has podido verlas? ¡No existen! Es como si les salieran alas, pues se van volando como las águilas.","No te sientes a la mesa de un tacaño,[79] ni codicies sus manjares,","que son como un pelo en la garganta.[80] «Come y bebe», te dirá, pero no te lo dirá de corazón.","Acabarás vomitando lo que hayas comido, y tus cumplidos no habrán servido de nada.","A oídos del necio jamás dirijas palabra, pues se burlará de tus sabios consejos.","No cambies de lugar los linderos antiguos, ni invadas la propiedad de los huérfanos,","porque su Defensor es muy poderoso y contra ti defenderá su causa.","Aplica tu corazón a la disciplina y tus oídos al conocimiento.","No dejes de disciplinar al joven, que de unos cuantos azotes no se morirá.","Dale unos buenos azotes, y así lo librarás del sepulcro.","Hijo mío, si tu corazón es sabio, también mi corazón se regocijará;","en lo íntimo de mi ser me alegraré cuando tus labios hablen con rectitud.","No envidies en tu corazón a los pecadores; más bien, muéstrate siempre celoso en el temor del SEÑOR.","Cuentas con una esperanza futura, la cual no será destruida.","Hijo mío, presta atención y sé sabio; mantén tu corazón en el camino recto.","No te juntes con los que beben mucho vino, ni con los que se hartan de carne,","pues borrachos y glotones, por su indolencia, acaban harapientos y en la pobreza.","Escucha a tu padre, que te engendró, y no desprecies a tu madre cuando sea anciana.","Adquiere la verdad y la sabiduría, la disciplina y el discernimiento, ¡y no los vendas!","El padre del justo experimenta gran regocijo; quien tiene un hijo sabio se solaza en él.","¡Que se alegren tu padre y tu madre! ¡Que se regocije la que te dio la vida!","Dame, hijo mío, tu corazón y no pierdas de vista mis caminos.","Porque fosa profunda es la prostituta, y estrecho pozo, la mujer ajena.","Se pone al acecho, como un bandido, y multiplica la infidelidad de los hombres.","¿De quién son los lamentos? ¿De quién los pesares? ¿De quién son los pleitos? ¿De quién las quejas? ¿De quién son las heridas gratuitas? ¿De quién los ojos morados?","¡Del que no suelta la botella de vino ni deja de probar licores!","No te fijes en lo rojo que es el vino, ni en cómo brilla en la copa, ni en la suavidad con que se desliza;","porque acaba mordiendo como serpiente y envenenando como víbora.","Tus ojos verán alucinaciones, y tu mente imaginará estupideces.","Te parecerá estar durmiendo en alta mar, acostado sobre el mástil mayor.","Y dirás: «Me han herido, pero no me duele. Me han golpeado, pero no lo siento. ¿Cuándo despertaré de este sueño para ir a buscar otro trago?»"],
  24: ["No envidies a los malvados, ni procures su compañía;","porque en su corazón traman violencia, y no hablan más que de cometer fechorías.","Con sabiduría se construye la casa; con inteligencia se echan los cimientos.","Con buen juicio se llenan sus cuartos de bellos y extraordinarios tesoros.","El que es sabio tiene gran poder, y el que es entendido aumenta su fuerza.","La guerra se hace con buena estrategia; la victoria se alcanza con muchos consejeros.","La sabiduría no está al alcance del necio, que en la asamblea del pueblo[81] nada tiene que decir.","Al que hace planes malvados lo llamarán intrigante.","Las intrigas del necio son pecado, y todos aborrecen a los insolentes.","Si en el día de la aflicción te desanimas, muy limitada es tu fortaleza.","Rescata a los que van rumbo a la muerte; detén a los que a tumbos avanzan al suplicio.","Pues aunque digas, «Yo no lo sabía», ¿no habrá de darse cuenta el que pesa los corazones? ¿No habrá de saberlo el que vigila tu vida? ¡Él le paga a cada uno según sus acciones!","Come la miel, hijo mío, que es deliciosa; dulce al paladar es la miel del panal.","Así de dulce sea la sabiduría a tu alma; si das con ella, tendrás buen futuro; tendrás una esperanza que no será destruida.","No aceches cual malvado la casa del justo, ni arrases el lugar donde habita;","porque siete veces podrá caer el justo, pero otras tantas se levantará; los malvados, en cambio, se hundirán en la desgracia.","No te alegres cuando caiga tu enemigo, ni se regocije tu corazón ante su desgracia,","no sea que el SEÑOR lo vea y no lo apruebe, y aparte de él su enojo.","No te alteres por causa de los malvados, ni sientas envidia de los impíos,","porque el malvado no tiene porvenir; ¡la lámpara del impío se apagará!","Hijo mío, teme al SEÑOR y honra al rey, y no te juntes con los rebeldes,","porque de los dos recibirás un castigo repentino ¡y quién sabe qué calamidades sobrevendrán!","También estos son dichos de los sabios: No es correcto ser parcial en el juicio.","Maldecirán los pueblos, y despreciarán las naciones, a quien declare inocente al culpable.","Pero bien vistos serán, y bendecidos, los que condenen al culpable.","Una respuesta sincera es como un beso en los labios.","Prepara primero tus faenas de cultivo y ten listos tus campos para la siembra; después de eso, construye tu casa.","No testifiques sin razón contra tu prójimo, ni mientas con tus labios.","No digas: «Le haré lo mismo que me hizo; le pagaré con la misma moneda».","Pasé por el campo del perezoso, por la viña del falto de juicio.","Había espinas por todas partes; la hierba cubría el terreno, y el lindero de piedras estaba en ruinas.","Guardé en mi corazón lo observado, y de lo visto saqué una lección:","Un corto sueño, una breve siesta, un pequeño descanso, cruzado de brazos…","¡y te asaltará la pobreza como un bandido, y la escasez, como un hombre armado!"],
  25: ["Estos son otros proverbios de Salomón, copiados por los escribas de Ezequías, rey de Judá.","Gloria de Dios es ocultar un asunto, y gloria de los reyes el investigarlo.","Tan impenetrable es el corazón de los reyes como alto es el cielo y profunda la tierra.","Quita la escoria de la plata, y de allí saldrá material para[82] el orfebre;","quita de la presencia del rey al malvado, y el rey afirmará su trono en la justicia.","No te des importancia en presencia del rey, ni reclames un lugar entre los magnates;","vale más que el rey te diga: «Sube acá», y no que te humille ante gente importante. Lo que atestigües con tus ojos","no lo lleves[83] de inmediato al tribunal, pues ¿qué harás si a fin de cuentas tu prójimo te pone en vergüenza?","Defiende tu causa contra tu prójimo, pero no traiciones la confianza de nadie,","no sea que te avergüence el que te oiga y ya no puedas quitarte la infamia.","Como naranjas de oro con incrustaciones de plata son las palabras dichas a tiempo.","Como anillo o collar de oro fino son los regaños del sabio en oídos atentos.","Como frescura de nieve en día de verano es el mensajero confiable para quien lo envía, pues infunde nuevo ánimo en sus amos.","Nubes y viento, y nada de lluvia, es quien presume de dar y nunca da nada.","Con paciencia se convence al gobernante. ¡La lengua amable quebranta hasta los huesos!","Si encuentras miel, no te empalagues; la mucha miel provoca náuseas.","No frecuentes la casa de tu amigo; no sea que lo fastidies y llegue a aborrecerte.","Un mazo, una espada, una aguda saeta, ¡eso es el falso testigo contra su amigo!","Confiar en gente desleal en momentos de angustia es como tener un diente cariado o una pierna quebrada.","Dedicarle canciones al corazón afligido es como echarle vinagre[84] a una herida o como andar desabrigado en un día de frío.","Si tu enemigo tiene hambre, dale de comer; si tiene sed, dale de beber.","Actuando así, harás que se avergüence de su conducta,[85] y el SEÑOR te lo recompensará.","Con el viento del norte vienen las lluvias; con la lengua viperina, las malas caras.","Más vale habitar en un rincón de la azotea que compartir el techo con mujer pendenciera.","Como el agua fresca a la garganta reseca son las buenas noticias desde lejanas tierras.","Manantial turbio, contaminado pozo, es el justo que flaquea ante el impío.","No hace bien comer mucha miel, ni es honroso buscar la propia gloria.","Como ciudad sin defensa y sin murallas es quien no sabe dominarse."],
  26: ["Ni la nieve es para el verano, ni la lluvia para la cosecha, ni los honores para el necio.","Como el gorrión sin rumbo o la golondrina sin nido, la maldición sin motivo jamás llega a su destino.","El látigo es para los caballos, el freno para los asnos, y el garrote para la espalda del necio.","No respondas al necio según su necedad, o tú mismo pasarás por necio.","Respóndele al necio como se merece, para que no se tenga por sabio.","Enviar un mensaje por medio de un necio es como cortarse los pies o sufrir[86] violencia.","Inútil es el proverbio en la boca del necio como inútiles son las piernas de un tullido.","Rendirle honores al necio es tan absurdo como atar una piedra a la honda.","El proverbio en la boca del necio es como espina en la mano del borracho.","Como arquero que hiere a todo el que pasa es quien contrata al necio en su casa.[87]","Como vuelve el perro a su vómito, así el necio insiste en su necedad.","¿Te has fijado en quien se cree muy sabio? Más se puede esperar de un necio que de gente así.","Dice el perezoso: «Hay una fiera en el camino. ¡Por las calles un león anda suelto!»","Sobre sus goznes gira la puerta; sobre la cama, el perezoso.","El perezoso mete la mano en el plato, pero le pesa llevarse el bocado a la boca.","El perezoso se cree más sabio que siete sabios que saben responder.","Meterse en pleitos ajenos es como agarrar a un perro por las orejas.","Como loco que dispara mortíferas flechas encendidas,","es quien engaña a su amigo y explica: «¡Tan solo estaba bromeando!»","Sin leña se apaga el fuego; sin chismes se acaba el pleito.","Con el carbón se hacen brasas, con la leña se prende fuego, y con un pendenciero se inician los pleitos.","Los chismes son como ricos bocados: se deslizan hasta las entrañas.","Como baño de plata[88] sobre vasija de barro son los labios zalameros de un corazón malvado.","El que odia se esconde tras sus palabras, pero en lo íntimo alberga perfidia.","No le creas, aunque te hable con dulzura, porque su corazón rebosa de abominaciones.[89]","Tal vez disimule con engaños su odio, pero en la asamblea se descubrirá su maldad.","Cava una fosa, y en ella caerás; echa a rodar piedras, y te aplastarán.","La lengua mentirosa odia a sus víctimas; la boca lisonjera lleva a la ruina."],
  27: ["No te jactes del día de mañana, porque no sabes lo que el día traerá.","No te jactes de ti mismo; que sean otros los que te alaben.","Pesada es la piedra, pesada es la arena, pero más pesada es la ira del necio.","Cruel es la furia, y arrolladora la ira, pero ¿quién puede enfrentarse a la envidia?","Más vale ser reprendido con franqueza que ser amado en secreto.","Más confiable es el amigo que hiere que el enemigo que besa.","Al que no tiene hambre, hasta la miel lo empalaga; al hambriento, hasta lo amargo le es dulce.","Como ave que vaga lejos del nido es el hombre que vaga lejos del hogar.","El perfume y el incienso alegran el corazón; la dulzura de la amistad fortalece el ánimo.[90]","No abandones a tu amigo ni al amigo de tu padre. No vayas a la casa de tu hermano cuando tengas un problema. Más vale vecino cercano que hermano distante.","Hijo mío, sé sabio y alegra mi corazón; así podré responder a los que me desprecian.","El prudente ve el peligro y lo evita; el inexperto sigue adelante y sufre las consecuencias.","Toma la prenda del que salga fiador por un extraño; retenla en garantía si la entrega por la mujer ajena.","El mejor saludo se juzga una impertinencia cuando se da a gritos y de madrugada.","Gotera constante en un día lluvioso es la mujer que siempre pelea.","Quien la domine podrá dominar el viento y retener[91] aceite en la mano.","El hierro se afila con el hierro, y el hombre en el trato con el hombre.","El que cuida de la higuera comerá de sus higos, y el que vela por su amo recibirá honores.","En el agua se refleja el rostro, y en el corazón se refleja la persona.","El sepulcro, la muerte y los ojos del hombre jamás se dan por satisfechos.","En el crisol se prueba la plata; en el horno se prueba el oro; ante las alabanzas, el hombre.","Aunque al necio lo muelas y lo remuelas, y lo machaques como al grano, no le quitarás la necedad.","Asegúrate de saber cómo están tus rebaños; cuida mucho de tus ovejas;","pues las riquezas no son eternas ni la fortuna está siempre segura.","Cuando se limpien los campos y brote el verdor, y en los montes se recoja la hierba,","las ovejas te darán para el vestido, y las cabras para comprar un campo;","tendrás leche de cabra en abundancia para que se alimenten tú y tu familia, y toda tu servidumbre."],
  28: ["El malvado huye aunque nadie lo persiga; pero el justo vive confiado como un león.","Cuando hay rebelión en el país, los caudillos se multiplican; cuando el gobernante es entendido, se mantiene el orden.","El gobernante[92] que oprime a los pobres es como violenta lluvia que arrasa la cosecha.","Los que abandonan la ley alaban a los malvados; los que la obedecen luchan contra ellos.","Los malvados nada entienden de la justicia; los que buscan al SEÑOR lo entienden todo.","Más vale pobre pero honrado que rico pero perverso.","El hijo entendido se sujeta a la ley; el derrochador deshonra a su padre.","El que amasa riquezas mediante la usura las acumula para el que se compadece de los pobres.","Dios aborrece hasta la oración del que se niega a obedecer la ley.","El que lleva a los justos por el mal camino caerá en su propia trampa; pero los íntegros heredarán el bien.","El rico se las da de sabio; el pobre pero inteligente lo desenmascara.","Cuando los justos triunfan, se hace gran fiesta; cuando los impíos se imponen, todo el mundo se esconde.","Quien encubre su pecado jamás prospera; quien lo confiesa y lo deja halla perdón.","¡Dichoso el que siempre teme al SEÑOR![93] Pero el obstinado caerá en la desgracia.","Un león rugiente, un oso hambriento, es el gobernante malvado que oprime a los pobres.","El gobernante falto de juicio es terrible opresor; el que odia las riquezas prolonga su vida.","El que es perseguido por[94] homicidio será un fugitivo hasta la muerte. ¡Que nadie le brinde su apoyo!","El que es honrado se mantendrá a salvo; el de caminos perversos caerá en la fosa.[95]","El que trabaja la tierra tendrá abundante comida; el que sueña despierto[96] solo abundará en pobreza.","El hombre fiel recibirá muchas bendiciones; el que tiene prisa por enriquecerse no quedará impune.","No es correcto mostrarse parcial con nadie. Hay quienes pecan hasta por un mendrugo de pan.","El tacaño ansía enriquecerse, sin saber que la pobreza lo aguarda.","A fin de cuentas, más se aprecia al que reprende que al que adula.","El que roba a su padre o a su madre, e insiste en que no ha pecado, amigo es de gente perversa.[97]","El que es ambicioso provoca peleas, pero el que confía en el SEÑOR prospera.","Necio es el que confía en sí mismo; el que actúa con sabiduría se pone a salvo.","El que ayuda al pobre no conocerá la pobreza; el que le niega su ayuda será maldecido.","Cuando triunfan los impíos, la gente se esconde; cuando perecen, los justos prosperan."],
  29: ["El que es reacio a las reprensiones será destruido de repente y sin remedio.","Cuando los justos prosperan, el pueblo se alegra; cuando los impíos gobiernan, el pueblo gime.","El que ama la sabiduría alegra a su padre; el que frecuenta rameras derrocha su fortuna.","Con justicia el rey da estabilidad al país; cuando lo abruma con tributos, lo destruye.","El que adula a su prójimo le tiende una trampa.","Al malvado lo atrapa su propia maldad, pero el justo puede cantar de alegría.","El justo se ocupa de la causa del desvalido; el malvado ni sabe de qué se trata.","Los insolentes conmocionan a la ciudad, pero los sabios apaciguan los ánimos.","Cuando el sabio entabla pleito contra un necio, aunque se enoje o se ría, nada arreglará.","Los asesinos aborrecen a los íntegros, y tratan de matar a los justos.","El necio da rienda suelta a su ira, pero el sabio sabe dominarla.","Cuando un gobernante se deja llevar por mentiras, todos sus oficiales se corrompen.","Algo en común tienen el pobre y el opresor: a los dos el SEÑOR les ha dado la vista.","El rey que juzga al pobre según la verdad afirma su trono para siempre.","La vara de la disciplina imparte sabiduría, pero el hijo malcriado avergüenza a su madre.","Cuando prospera el impío, prospera el pecado, pero los justos presenciarán su caída.","Disciplina a tu hijo, y te traerá tranquilidad; te dará muchas satisfacciones.","Donde no hay visión, el pueblo se extravía; ¡dichosos los que son obedientes a la ley!","No solo con palabras se corrige al siervo; aunque entienda, no obedecerá.","¿Te has fijado en los que hablan sin pensar? ¡Más se puede esperar de un necio que de gente así!","Quien consiente a su criado cuando este es niño al final habrá de lamentarlo.[98]","El hombre iracundo provoca peleas; el hombre violento multiplica sus crímenes.","El altivo será humillado, pero el humilde será enaltecido.","El cómplice del ladrón atenta contra sí mismo; aunque esté bajo juramento,[99] no testificará.","Temer a los hombres resulta una trampa, pero el que confía en el SEÑOR sale bien librado.","Muchos buscan el favor del gobernante, pero solo el SEÑOR hace justicia.","Los justos aborrecen a los malvados, y los malvados aborrecen a los justos."],
  30: ["Dichos de Agur hijo de Jaqué. Oráculo.[100] Palabras de este varón: «Cansado estoy, oh Dios; cansado estoy, oh Dios, y débil.[101]","»Soy el más ignorante de todos los hombres; no hay en mí discernimiento humano.","No he adquirido sabiduría, ni tengo conocimiento del Dios santo.","»¿Quién ha subido a los cielos y descendido de ellos? ¿Quién puede atrapar el viento en su puño o envolver el mar en su manto? ¿Quién ha establecido los límites de la tierra? ¿Quién conoce su nombre o el de su hijo?","»Toda palabra de Dios es digna de crédito; Dios protege a los que en él buscan refugio.","No añadas nada a sus palabras, no sea que te reprenda y te exponga como a un mentiroso.","»Solo dos cosas te pido, SEÑOR; no me las niegues antes de que muera:","Aleja de mí la falsedad y la mentira; no me des pobreza ni riquezas, sino solo el pan de cada día.","Porque teniendo mucho, podría desconocerte y decir: “¿Y quién es el SEÑOR?” Y teniendo poco, podría llegar a robar y deshonrar así el nombre de mi Dios.","»No ofendas al esclavo delante de su amo, pues podría maldecirte y sufrirías las consecuencias.","»Hay quienes maldicen a su padre y no bendicen a su madre.","Hay quienes se creen muy puros, pero no se han purificado de su impureza.","Hay quienes se creen muy importantes, y a todos miran con desdén.","Hay quienes tienen espadas por dientes y cuchillos por mandíbulas; para devorar a los pobres de la tierra y a los menesterosos de este mundo.","»La sanguijuela tiene dos hijas que solo dicen: “Dame, dame”. »Tres cosas hay que nunca se sacian, y una cuarta que nunca dice “¡Basta!”:","el sepulcro, el vientre estéril, la tierra, que nunca se sacia de agua, y el fuego, que no se cansa de consumir.","»Al que mira con desdén a su padre, y rehúsa obedecer a su madre, que los cuervos del valle le saquen los ojos y que se lo coman vivo los buitres.","»Tres cosas hay que me causan asombro, y una cuarta que no alcanzo a comprender:","el rastro del águila en el cielo, el rastro de la serpiente en la roca, el rastro del barco en alta mar, y el rastro del hombre en la mujer.","»Así procede la adúltera: come, se limpia la boca, y afirma: “Nada malo he cometido”.","»Tres cosas hacen temblar la tierra, y una cuarta la hace estremecer:","el siervo que llega a ser rey, el necio al que le sobra comida,","la mujer rechazada que llega a casarse, y la criada que suplanta a su señora.","»Cuatro cosas hay pequeñas en el mundo, pero que son más sabias que los sabios:","las hormigas, animalitos de escasas fuerzas, pero que almacenan su comida en el verano;","los tejones, animalitos de poca monta, pero que construyen su casa entre las rocas;","las langostas, que no tienen rey, pero que avanzan en formación perfecta;","las lagartijas, que se atrapan con la mano, pero que habitan hasta en los palacios.","»Tres cosas hay que caminan con garbo, y una cuarta de paso imponente:","el león, poderoso entre las bestias, que no retrocede ante nada;","el gallo engreído,[102] el macho cabrío, y el rey al frente de su ejército.[103]","»Si como un necio te has engreído, o si algo maquinas, ponte a pensar[104]","que batiendo la leche se obtiene mantequilla, que sonándose fuerte sangra la nariz, y que provocando la ira se acaba peleando»."],
  31: ["Los dichos del rey Lemuel. Oráculo mediante el cual[105] su madre lo instruyó:","«¿Qué pasa, hijo mío? ¿Qué pasa, hijo de mis entrañas? ¿Qué pasa, fruto de mis votos[106] al SEÑOR?","No gastes tu vigor en las mujeres, ni tu fuerza[107] en las que arruinan a los reyes.","»No conviene que los reyes, oh Lemuel, no conviene que los reyes se den al vino, ni que los gobernantes se entreguen al licor,","no sea que al beber se olviden de lo que la ley ordena y priven de sus derechos a todos los oprimidos.","Dales licor a los que están por morir, y vino a los amargados;","¡que beban y se olviden de su pobreza! ¡que no vuelvan a acordarse de sus penas!","»¡Levanta la voz por los que no tienen voz! ¡Defiende los derechos de los desposeídos!","¡Levanta la voz, y hazles justicia! ¡Defiende a los pobres y necesitados!»","[108]Mujer ejemplar,[109] ¿dónde se hallará? ¡Es más valiosa que las piedras preciosas!","Su esposo confía plenamente en ella y no necesita de ganancias mal habidas.","Ella le es fuente de bien, no de mal, todos los días de su vida.","Anda en busca de lana y de lino, y gustosa trabaja con sus manos.","Es como los barcos mercantes, que traen de muy lejos su alimento.","Se levanta de madrugada, da de comer[110] a su familia y asigna tareas a sus criadas.","Calcula el valor de un campo y lo compra; con sus ganancias[111] planta un viñedo.","Decidida se ciñe la cintura[112] y se apresta para el trabajo.","Se complace en la prosperidad de sus negocios, y no se apaga su lámpara en la noche.","Con una mano sostiene el huso y con la otra tuerce el hilo.","Tiende la mano al pobre, y con ella sostiene al necesitado.","Si nieva, no tiene que preocuparse de su familia, pues todos están bien abrigados.","Las colchas las cose ella misma, y se viste de púrpura y lino fino.","Su esposo es respetado en la comunidad;[113] ocupa un puesto entre las autoridades del lugar.","Confecciona ropa de lino y la vende; provee cinturones a los comerciantes.","Se reviste de fuerza y dignidad, y afronta segura el porvenir.","Cuando habla, lo hace con sabiduría; cuando instruye, lo hace con amor.","Está atenta a la marcha de su hogar, y el pan que come no es fruto del ocio.","Sus hijos se levantan y la felicitan; también su esposo la alaba:","«Muchas mujeres han realizado proezas, pero tú las superas a todas».","Engañoso es el encanto y pasajera la belleza; la mujer que teme al SEÑOR es digna de alabanza.","¡Sean reconocidos[114] sus logros, y públicamente[115] alabadas sus obras!"],
};
